INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_LASEMA', 'Lasema Package (12hr)', 'Full use of jacuzzi, sauna, kilns, full body massage, 12 hr max stay', 12, 1, false, true, false FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_LASEMA_COUPLE', 'Lasema Couple Package', 'Private couple room, 60-min massage + jacuzzi each, wine, kilns, 12 hr stay', 12, 2, true, true, true FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_MASSAGE_COUPLE', 'Massage Couple Package', 'Private couple room, 60-min massage + 60-min jacuzzi, wine, 3 hr stay', 3, 2, true, true, true FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_SAUNA', 'Sauna Package', 'Jacuzzi + sauna + shower, 3 hr max stay (no massage)', 3, 1, false, false, false FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_MASSAGE', 'Massage Package (3hr)', 'Jacuzzi + sauna + 60-min full body massage, 3 hr max stay', 3, 1, false, true, false FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room)
SELECT id, 'PKG_JJIMJILBANG', 'Jjimjilbang Package', 'All kilns, sleeping cave, gym, entertainment, 12 hr max stay (no massage)', 12, 1, false, false, false FROM organizations WHERE slug='lasema';

INSERT INTO package_tiers (package_id, service_id, weekday_price, weekend_price)
SELECT p.id, s.id, 2000, 2200 FROM packages p JOIN services_catalogue s ON s.organization_id=p.organization_id AND s.code='FOOT_REFLEX' WHERE p.code='PKG_LASEMA';
